let currentLang = localStorage.getItem('fodmapp-lang') || 'en';

function applyLang(lang) {
  currentLang = lang;
  localStorage.setItem('fodmapp-lang', lang);
  document.documentElement.lang = lang === 'nb' ? 'no' : lang;
  const t = T[lang];
  if (!t) return;
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const k = el.dataset.i18n;
    if (t[k]) el.innerHTML = t[k];
  });
  document.querySelectorAll('[data-i18n-ph]').forEach(el => {
    const k = el.dataset.i18nPh;
    if (t[k]) el.placeholder = t[k];
  });
  updateLangGrid();
}

function resetToEnglish() {
  localStorage.setItem('fodmapp-lang', 'en');
  location.reload();
}

function buildLangGrid() {
  const g = document.getElementById('langGrid');
  if (!g) return;
  g.innerHTML = '';
  LANGS.forEach(l => {
    const o = document.createElement('div');
    o.className = 'lang-option' + (l.code === currentLang ? ' active' : '');
    o.innerHTML = '<span class="lang-flag">' + l.flag + '</span>' + l.name;
    o.onclick = () => selectLang(l.code);
    g.appendChild(o);
  });
}

function updateLangGrid() {
  const options = document.querySelectorAll('.lang-option');
  options.forEach((o, i) => {
    if (LANGS[i]) o.classList.toggle('active', LANGS[i].code === currentLang);
  });
}

function selectLang(code) {
  if (code === 'en') { resetToEnglish(); return; }
  if (T[code]) applyLang(code);
  else { currentLang = code; localStorage.setItem('fodmapp-lang', code); updateLangGrid(); }
  closeLangModalForce();
}

function openLangModal() { document.getElementById('langOverlay').classList.add('open'); }
function closeLangModal(e) { if (e && e.target === document.getElementById('langOverlay')) closeLangModalForce(); }
function closeLangModalForce() { document.getElementById('langOverlay').classList.remove('open'); }

// Init
buildLangGrid();
if (currentLang !== 'en' && T[currentLang]) applyLang(currentLang);
else if (currentLang !== 'en') updateLangGrid();
